// Thin, hand-authored openapi-fetch wrapper over the GENERATED `schema.d.ts`
// types (monorepo §4). The schema types are regenerated by
// `task contracts:generate` and never hand-edited; this wrapper only binds
// openapi-fetch to the generated `paths` so consumers get a fully typed client
// from a single import. It stays intentionally minimal — no transport policy,
// auth, or business logic lives here.
import createClient, { type ClientOptions } from "openapi-fetch";
import type { paths } from "./schema";

export type GatewayClient = ReturnType<typeof createClient<paths>>;

/** Create a typed gateway client bound to the generated OpenAPI paths. */
export function createGatewayClient(options?: ClientOptions): GatewayClient {
  return createClient<paths>(options);
}
